const kilos_data = flow.get('kilos_data') || [];
const estado = (Array.isArray(msg.payload) && msg.payload[0]) ? msg.payload[0] : {};
const fecha = new Date().toISOString().slice(0, 10);
const now = new Date().toISOString().slice(0, 19).replace('T', ' ');

// INSERT para molienda_tiempo_real
let msg1 = null;
if (kilos_data.length > 0) {
    const values = kilos_data.map(r =>
        `('${fecha}', '${r.hora_inicio}', ${parseInt(r.kilos)||0}, ${parseInt(r.pesadas)||0}, '${now}')`
    ).join(', ');
    msg1 = {
        topic: '',
        payload: `INSERT INTO molienda_tiempo_real (fecha, hora_inicio, neto_cana_kg, pesadas_count, actualizado) VALUES ${values} ON DUPLICATE KEY UPDATE neto_cana_kg=VALUES(neto_cana_kg), pesadas_count=VALUES(pesadas_count), actualizado=VALUES(actualizado)`
    };
}

// INSERT/UPDATE para molienda_estado_actual
const pre_ingreso = parseInt(estado.pre_ingreso) || 0;
const ultima_raw = estado.ultima_pesada || null;
const ultima = ultima_raw ? String(ultima_raw).substring(0, 8) : null;
const ultima_sql = ultima ? `'${ultima}'` : 'NULL';
const msg2 = {
    topic: '',
    payload: `INSERT INTO molienda_estado_actual (id, pre_ingreso, ultima_pesada, actualizado) VALUES (1, ${pre_ingreso}, ${ultima_sql}, '${now}') ON DUPLICATE KEY UPDATE pre_ingreso=${pre_ingreso}, ultima_pesada=${ultima_sql}, actualizado='${now}'`
};

return [msg1, msg2];
